import{_ as n,j as i,o as t,v as h}from"./chunks/framework.dn0DPyqd.js";const a=JSON.parse('{"title":"Fallacies of distributed computing - Những sai lầm khi sử dụng distributed computing","description":"Từ những phiên bản đầu tiên khi Kafka được Open Source đến phiên bản 2.3.1, mặc định Kafka producer khi gửi các Record có key là null sẽ thực hiện Round Robin Partition","frontmatter":{"footer":true,"title":"Fallacies of distributed computing - Những sai lầm khi sử dụng distributed computing","description":"Từ những phiên bản đầu tiên khi Kafka được Open Source đến phiên bản 2.3.1, mặc định Kafka producer khi gửi các Record có key là null sẽ thực hiện Round Robin Partition","authors":["lethanh"],"date":"2024-10-09T00:00:00.000Z","outline":"deep","image":"/assets/KafkaProducer12.qYn0oVGH.png","draft":true},"headers":[{"level":2,"title":"Những sai lầm.","slug":"nhung-sai-lam","link":"#nhung-sai-lam","children":[{"level":3,"title":"The network is reliable","slug":"the-network-is-reliable","link":"#the-network-is-reliable","children":[{"level":4,"title":"Hệ thống của chúng ta Nên làm gì để đảm bảo The network is reliable.","slug":"he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable","link":"#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable","children":[]}]},{"level":3,"title":"Latency is zero","slug":"latency-is-zero","link":"#latency-is-zero","children":[{"level":4,"title":"Hệ thống của chúng ta Nên làm gì để đảm bảo Latency is zero.","slug":"he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-latency-is-zero","link":"#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-latency-is-zero","children":[]}]},{"level":3,"title":"Bandwidth is infinite","slug":"bandwidth-is-infinite","link":"#bandwidth-is-infinite","children":[{"level":4,"title":"Các thiệt hại khi đạt giới hạn Bandwidth hoặc lạm dụng Bandwidth.","slug":"cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth","link":"#cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth","children":[]},{"level":4,"title":"Hệ thống của chúng ta Nên làm gì để đảm bảo Bandwidth is infinite.","slug":"he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-bandwidth-is-infinite","link":"#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-bandwidth-is-infinite","children":[]}]}]},{"level":2,"title":"Network is secure","slug":"network-is-secure","link":"#network-is-secure","children":[{"level":3,"title":"Hệ thống của chúng ta Nên làm gì để đảm bảo Network is secure.","slug":"he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure","link":"#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure","children":[]},{"level":3,"title":"Topology doesn\'t change","slug":"topology-doesn-t-change","link":"#topology-doesn-t-change","children":[]}]}],"relativePath":"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md","filePath":"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md","lastUpdated":1730336865000}'),c={name:"blog/2024-10-09-Fallacies-of-distributed-computing-nhung-sai-lam-cua-khi-su-dung-distributed-computing.md"},l=[h('<p>Fallacies of distributed computing là một tập hợp các khẳng định được tập hợp bởi <a href="https://en.wikipedia.org/wiki/L._Peter_Deutsch" target="_blank" rel="noreferrer">L. Peter Deutsch</a> và một số người tại <a href="https://en.wikipedia.org/wiki/Sun_Microsystems" target="_blank" rel="noreferrer">Sun Microsystems</a> mô tả về những giả định sai lầm của các lập tình viên đanng làm việc với ứng dụng phân tán.</p><p>Tuy nhiên trong bài viết này mình sẽ dựa vào khái niệm Fallacies of distributed computing để mapping nó về phát triển ứng dụng, phần mềm trong hệ thống microservices.</p><p>Điều này sẽ giúp các bạn có cái nhìn tổng quan về những sai lầm mà các lập trình viên hay gặp phải khi phát triển và triển khai ứng dụng của mình lên cho người dùng sử dụng.</p><h2 id="nhung-sai-lam" tabindex="-1">Những sai lầm. <a class="header-anchor" href="#nhung-sai-lam" aria-label="Permalink to &quot;Những sai lầm.&quot;">​</a></h2><h3 id="the-network-is-reliable" tabindex="-1">The network is reliable <a class="header-anchor" href="#the-network-is-reliable" aria-label="Permalink to &quot;The network is reliable&quot;">​</a></h3><p><strong>The network is reliable</strong>: Dịch tiếng việt là <code>Mạng lưới đáng tin cậy</code>. Đây là 1 sai lầm nghiêm trọng nhưng cũng hay xảy ra nhất.</p><p>Rất nhiều lập trình viên tin rằng các kết nối mạng đến node hoặc hệ thống khác sẽ tốt và luôn không có vấn đề gì xảy ra. Tuy nhiên kết nối mạng rất sẽ bị lỗi bởi nhiều nguyên nhân như mất kết nối, không có quyền, lỗi phần cứng...etc..</p><p>Hệ thống cần có một cơ chế linh loạt bao gồm đầy đủ các tính năng dự phòng khi mất kết nối đến các hệ thống khác.</p><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/TL91JWCn3Bpd5POu8t7U0q9qMu44257w0BCrswZPfDZUhlfxd3IKLeYSaXbxF9daJXHPno4usVguGyO1Fh3Rzfp6k9wba1YkvlFvVJixgv0DhjFaOm-V68JE66HEKssxAUkSx3JnKW-102UID91pwjMExnk25z8fyHQym1i5Zn-6Bp04x0xEbLPO2J6WmAgUMzfJIBiZs3gtWkjRM1v4QMXWIN5jIbyZYReZcEawfe5tnYY3LsXHqM7GauC5-Z0oER3rWvq9prACrAbF4PwIQUUoN_rL0tCBWU6PHB0dHvRGIMOvTftXVwI9zyGDB19FoEkZfQ9RY0lVzLwoIr7-zTXQWhdnekx2v1lfoF4uoHITYqa9sFSRXVHPQqlReuXb21sEafyyrcbZvF9CFdWzDANo-cIbIx6tt2sZIZpOjUngP3-cX2iLVoKUl4WEqvSv5N-CcXbLYfhLIk9xcvJDGlRgt9rjxUj-0m00" alt="uml diagram"></div><h4 id="he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable" tabindex="-1">Hệ thống của chúng ta Nên làm gì để đảm bảo <code>The network is reliable</code>. <a class="header-anchor" href="#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-the-network-is-reliable" aria-label="Permalink to &quot;Hệ thống của chúng ta Nên làm gì để đảm bảo `The network is reliable`.&quot;">​</a></h4><details class="details custom-block"><summary>Chi tiết</summary><p>Sẽ có rất nhiều cách để đảm bảo hệ thống của chúng ta là <code>network is reliable</code> khi chúng ta là phụ thuộc của các hệ thống khác, dưới đây là một số ví dụ.</p><ul><li>Cung cấp load balance để phân tải hệ thống, phòng ngừa hệ thống sập.</li><li>Auto scale để mở rộng quy mô tự động.</li><li>Cung cấp tính năng sử dụng Asynchronous messaging.</li><li>Sử dụng CDN và deploy hệ thống ở nhiều khu vực.</li><li>Một điều quan trọng đó là ngay khi thiết kế hệ thống hoặc lập trình viên code thì phải có tư tưởng là sẽ có lỗi mạng.</li><li>...</li></ul></details><h3 id="latency-is-zero" tabindex="-1">Latency is zero <a class="header-anchor" href="#latency-is-zero" aria-label="Permalink to &quot;Latency is zero&quot;">​</a></h3><p><strong>Latency is zero</strong> : Dịch tiếng việt là độ trễ là 0.</p><p>Tình huống được kiểm tra phổ biến bởi các lập trình viên là các hệ thống phụ thuộc không hoạt động. Tuy nhiên một trong những trường hợp hay xảy ra nhưng ít lập trình viên nghĩ đến đó là các phụ thuộc hoạt động chậm.</p><p>Các hệ thống có thể bị đột ngột tăng lượng người sử dụng đột biến, mạng hệ thống chậm, mạng kết nối chậm... everything.., điều này sẽ tác động đến các hệ thống gửi phản hồi(Response) lại cho người dùng chậm hơn.</p><p>Hệ thống cần có các cơ chế để phòng ngừa tình trạng các hệ thống khác phản hồi chậm. <img src="/assets/network-latency.WLz64lxW.png" alt="img"></p><h4 id="he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-latency-is-zero" tabindex="-1">Hệ thống của chúng ta Nên làm gì để đảm bảo <code>Latency is zero</code>. <a class="header-anchor" href="#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-latency-is-zero" aria-label="Permalink to &quot;Hệ thống của chúng ta Nên làm gì để đảm bảo `Latency is zero`.&quot;">​</a></h4><details class="details custom-block"><summary>Chi tiết</summary><p>Sẽ có rất nhiều cách để đảm bảo hệ thống của chúng ta là <code>Latency is zero</code> khi chúng ta là phụ thuộc của các hệ thống khác, dưới đây là một số ví dụ.</p><ul><li>Cung cấp load balance để phân tải hệ thống, phòng ngừa quá nhiều yêu cầu gây chậm chạp hệ thống.</li><li>Auto scale để mở rộng quy mô tự động.</li><li>Tư duy luôn luôn nhớ rằng gọi đến một phụ thuộc khác thì luôn luôn có độ trễ, và nó có thể tính bằng phút.</li><li>Sử dụng Caching để giảm tải cho hệ thống.</li><li>Sử dụng Asynchronous Processing để xử lý các tác vụ không cần thiết.</li><li>Sử dụng CDN để cung cấp tốc độ liên lạc nhanh nhất từ người dùng đến hệ thống.</li><li>Sử dụng Rate Limiting để giới hạn tốc độ truy cập của người dùng.</li><li>Sử dụng QoS để ưu tiên các tính năng quan trọng hơn khi sự cố xảy ra.</li><li>...</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/RLF1Rjim3BthAuZs761d7uQkTeOMw8fkRYwxiJ8J2t74LgGRf5y_IauN7QgBHJwIZu-KRqGnwNoOdEn3VCM41tX1lzybdkFGyiG9hjVhzMtNLX4oui3747UmnKceGZ0bFfxJlfLJWruvzNgQ2F18mWToJeEQ-O1AqPyW2FobnCwLKDW89K21pTdkw9qcVbsSdNCRM7s7_YHAXmPwYWFyeRUPHDtYpF03ut2B4qPFgO4kYARmCYiLmDLeZcwxnrmflHFqYXeyj1ojDtM6v81DOnmwfmWj-f66_tX5MP06sf7yVZ4SJhhSu2we0pkBzLN53XKTsLpFCR-2I4cvC9GEJSvFKZyk2IMWkAiMUfiQVOLVI1UsEDG2VipAlSSfKvGltCTjGXlTx2s9gj3Vt3Vmb0AdeE63u3dXTXjyNKnEqO-98y_obDYJYBsS1kum3bRvaUEgpSd60yyeUt4kikqdXTsemDkpx4M09difkq02oa1HSZCPkAfUq8UzeAkck5Tbox1is5ZFJjlbvytcTF5dtIknHYukq_S9LZhW8YJF3dB3pjtOrNwbVm00" alt="uml diagram"></div></details><h3 id="bandwidth-is-infinite" tabindex="-1">Bandwidth is infinite <a class="header-anchor" href="#bandwidth-is-infinite" aria-label="Permalink to &quot;Bandwidth is infinite&quot;">​</a></h3><p>Có lẽ bạn chưa biết, các VPS hoặc cloud ở Việt Nam thường có Bandwidth tối đa là 100 Mb/s. Nếu ứng dụng chúng ta sử dụng Bandwidth vượt quá giới hạn ứng dụng của chúng ta có thể bị tắc nghẽn. Và tất nhiên chính thiết bị phần cứng của chúng ta cũng có giới hạn. Nếu tốc độ vượt quá giới hạn phần cứng thì hệ thống của chúng ta sẽ bị tắc nghẽn.</p><ul><li>Ví dụ 1: Ứng dụng của chúng ta cung cấp chức năng xem phim, nếu có quá nhiều người xem phim cùng lúc thì hệ thống của chúng ta sẽ bị tắc nghẽn.</li></ul><h4 id="cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth" tabindex="-1">Các thiệt hại khi đạt giới hạn Bandwidth hoặc lạm dụng Bandwidth. <a class="header-anchor" href="#cac-thiet-hai-khi-đat-gioi-han-bandwidth-hoac-lam-dung-bandwidth" aria-label="Permalink to &quot;Các thiệt hại khi đạt giới hạn Bandwidth hoặc lạm dụng Bandwidth.&quot;">​</a></h4><ul><li>Có thể gây tắc nghẽn hệ thống, request người dùng sẽ không thể đáp ứng hoặc đáp ứng chậm.</li><li>Đa số các bên cho thuê VPS và Cloud đều sẽ tính phí mạng, nếu lạm dụng mạng có thể dẫn đến chi phí cao.</li><li>Lạm dụng băng thông có thể làm tăng nguy cơ bị tấn công từ chối dịch vụ (DDoS), làm giảm khả năng bảo mật của hệ thống.</li><li>Khi băng thông bị giới hạn, khả năng mở rộng của hệ thống cũng bị ảnh hưởng, làm giảm khả năng phục vụ số lượng lớn người dùng cùng lúc.</li></ul><h4 id="he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-bandwidth-is-infinite" tabindex="-1">Hệ thống của chúng ta Nên làm gì để đảm bảo <code>Bandwidth is infinite</code>. <a class="header-anchor" href="#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-bandwidth-is-infinite" aria-label="Permalink to &quot;Hệ thống của chúng ta Nên làm gì để đảm bảo `Bandwidth is infinite`.&quot;">​</a></h4><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Cung cấp load balance để phân tải hệ thống.</li><li>Sử dụng CDN để cung cấp tốc độ liên lạc nhanh nhất từ người dùng đến hệ thống.</li><li>Sử dụng CDN cho các file tĩnh như hình ảnh, video, css, js...</li><li>Sử dụng Cache để giảm tải cho hệ thống.</li><li>Giới hạn tốc độ download và upload của người dùng.</li><li>QoS: Cấu hình phòng ngừa để ưu tiên các tính năng trọng hơn khi sự cố xảy ra. Để đảm bảo rằng các dịch vụ quan trọng nhất của bạn vẫn hoạt động tốt nhất có thể.</li><li>Giảm kích thước của các tài nguyên như hình ảnh, script và stylesheet để giảm lượng dữ liệu truyền tải</li><li>Tự động mở rộng hạ tầng dựa trên nhu cầu lưu lượng để xử lý các tải khác nhau một cách hiệu quả.</li><li>Người thiết kế hệ thống và người phát triển phần mềm cần phải có tư duy về việc giới hạn băng thông và tối ưu hóa băng thông.</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/RLFDRjim3BxhAOZk761d7uOkTeOEw8QjNXw0bUcOY2rb4jsWU_fHajTeG7KnoO__7tqV1OEiospYcTq50oxmZFPy2dvrG-jd7-33uN3OTstb4ISS_9NT2KQS8rK8Xk2lMzZ7_6hGYW-zlCu4UANe5p96M5JTenkkFCW47E6h6zcnA9W3u1Wf04OuRdf7BpJxIp5snXnXzmdwroYqDD2J6-29VgyKnHHZWXyz3dkSqLaA3NGS9V3pAfG1KwF9k-s-fqpXXQ0N5BRGUYVan2YI78wDrf0rE6ZHJZIyuLN9Z3JGJcJFHJ4uIv7WWSM0lgAzbx53GKEwtStd6yUOGsuLSeSwpXSIEvM0x93DLGkzRetUmsz5IpKtr0Fyz7q3FmBxmC9_27u574UsbSVdLNnlSKvDv6_YBg0kTxMQbkfj-EKIA4RshdbJIjcRqnCAFVAYt6l2B1JoDpwZCSuhPu5Fau0VjrMKeIHey8afWdWW5rFv1DpzTrkytTPTay5TvXyAzthFcr5P_YVf1czstSWcfSbtKKUkWcuJRfOqJXaZUQN3JEsRUvNqZ_iB" alt="uml diagram"></div></details><h2 id="network-is-secure" tabindex="-1">Network is secure <a class="header-anchor" href="#network-is-secure" aria-label="Permalink to &quot;Network is secure&quot;">​</a></h2><p>Đây là một trong những sai lầm nhưng các lập trình viên lại không chú ý đến. Bởi vì ngày nay(2024) các lập trình viên ở Việt Nam chú trọng nhiều vào việc phát triển chức năng, tối ưu hóa hệ thống, tối ưu hóa tốc độ, tối ưu hóa bộ nhớ, tối ưu hóa cơ sở dữ liệu... nhưng ít chú trọng vào việc bảo mật hệ thống.</p><p>Dù lập trình viên có chú ý bảo mật hệ thống trong code của mình rất tốt nhưng khi dữ liệu đi qua mạng thì không được mã hóa thì hệ thống của chúng ta vẫn không an toàn.</p><p>Hiện tại khi dữ liệu đi qua mạng thì có rất nhiều cách để hacker hoặc các hệ thống trung gian đứng giữa đánh cắp dữ liệu hoặc thay đổi dữ liệu gây ra vấn đề giả mạo yêu cầu hoặc truy cập trái phép.</p><p>Một trong những khái niệm phổ biến về kiểu tấn công này là man-in-the-middle attack.</p><p>Vì vậy hệ thống cần có các cơ chế bảo mật ở tầng mạng để đảm bảo dữ liệu của chúng ta không bị đánh cắp hoặc thay đổi.</p><p>Vấn đề không phải là dữ liệu của bạn có bị đánh cắp hay không; mà là khi nào dữ liệu sẽ bị đánh cắp.</p><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Dù hệ thống có an toàn đến đâu, bạn có vò đầu bứt tai để bảo mật hệ thống của mình thì vẫn luôn có nguy cơ bị tấn công và bị đánh cắp dữ liệu hoặc thay đổi dữ liệu.</li><li>Vì vậy hệ thống cần có các cơ chế bảo mật ở tầng mạng để đảm bảo dữ liệu của chúng ta không bị đánh cắp hoặc thay đổi.</li></ul></details><h3 id="he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure" tabindex="-1">Hệ thống của chúng ta Nên làm gì để đảm bảo <code>Network is secure</code>. <a class="header-anchor" href="#he-thong-cua-chung-ta-nen-lam-gi-đe-đam-bao-network-is-secure" aria-label="Permalink to &quot;Hệ thống của chúng ta Nên làm gì để đảm bảo `Network is secure`.&quot;">​</a></h3><details class="details custom-block"><summary>Chi tiết</summary><ul><li>Sử dụng HTTPS để mã hóa dữ liệu truyền tải giữa người dùng và hệ thống.</li><li>Sử dụng VPN để mã hóa dữ liệu truyền tải giữa các hệ thống.</li><li>Sử dụng SSH để truy cập an toàn vào hệ thống.</li><li>Sử dụng Rate Limiting để giới hạn tốc độ truy cập của người dùng.</li><li>Sử dụng Encryption để mã hóa dữ liệu truyền tải giữa các hệ thống hoặc giữa người dùng và hệ thống.</li><li>Sử dụng Multi-Factor Authentication để bảo vệ tài khoản người dùng.</li><li>Người thiết kế hệ thống và người phát triển phần mềm cần phải có tư duy về việc bảo mật dữ liệu khi gửi qua mạng.</li><li>...etc...</li></ul><div data-svg="data-diagram-plantuml" class="diagram-m"><img src="https://www.plantuml.com/plantuml/svg/VLDDRy8m3BtdLrZRPJjKsfd310Ecxi0qhNHtqng8Q1Dakwluzqk_Hc4JEJbvp_RpHwQYo5gLXP63TKTaB663sM77ldBvt1UUuNwvNBuivYE6x37tjNKxs68XD4AGsTUzsrDxnc2cdXCz5GHOa_YIZ56huVfEMdi-W1L8AAiu02qPKY4654ZxUnoqTI-nCIb4puFh93Yw79OkuzDHAOS5AfeXRk0b9r4g9x1cT59QlQPs-4N4Jyh8VjEDe6b3qehTYFD9SlHEcX8AXHMwoBf8znIjR9w7McUgeGW3uSGNwTwS4cTqr2xDBs5G7Xof3AXwM52RxKmyguydLthX8NLCcEEce4T3OLvzZuTMY5ZlsYZ_jElLSutyfx6NEM-s8Op56EULWErkh-2tlMSNH1cLTfQagOkSDCDlWBlHJaYhzsxI0X74w_L7qjjV7--zbIHnR_KYXgeYM5M5skYrMw5P5ORXr6ROCfgjQTIPQR32H_W1" alt="uml diagram"></div></details><h3 id="topology-doesn-t-change" tabindex="-1">Topology doesn&#39;t change <a class="header-anchor" href="#topology-doesn-t-change" aria-label="Permalink to &quot;Topology doesn&#39;t change&quot;">​</a></h3><ul><li></li></ul>',37)];const g=n(c,[["render",function(n,h,a,c,g,e){return t(),i("div",null,l)}]]);export{a as __pageData,g as default};
